onClick:
{{
  (() => {
// 1. Sinaliza atividade para o sistema de segurança (reseta os 15 min)
 JSutils.resetInactivityTimer();		
// 2 - Definimos os dados que vêm dos inputs do seu formulário/container
		const formData = {
      serv001_id: InputID.text, 
      serv001_desc: InputDescricao.text?.trim().toUpperCase(),
      serv001_valor_custo: InputCusto.text,			
      serv001_valor_venda: InputValor.text,	
      serv001_estoque_atual: InputEstoqueAtual.text,
      serv001_tipo: Select1Tipo.selectedOptionValue,
      serv001_controla_estoque: Select1Controla.selectedOptionValue,
      serv001_unid001_id: Select1Unidade.selectedOptionValue		

    };

    if (appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") {
      return JSconfirmation.showModal({
        action: "Insert",
        message: "Deseja salvar este novo registro?",
        icon: "plus",
        color: "green",
				row: formData
      });
    } else {
      return JSconfirmation.showModal({
        action: "Update",
        message: "Deseja salvar as alterações deste registro?",
        icon: "edit",
        color: "orange",
		    row: formData
      });
    }
  })()
}}
